import psycopg2

def connect():
    connection = psycopg2.connect(
        host="your_host",
        database="your_database",
        user="your_user",
        password="your_password"
    )
    return connection

def search_users(username=None, email=None, role=None, status=None, connection=None):
    cursor = connection.cursor()
    query = """
        SELECT * FROM users
        WHERE 1=1
    """
    filters = {
        'username': username,
        'email': email,
        'role': role,
        'status': status,
    }
    for key, value in filters.items():
        if value is not None:
            query += f" AND {key}='{value}'"

    cursor.execute(query)
    results = cursor.fetchall()
    return results

